ReturnCode_t LAN866XClientImpl::WriteAndReadSpiExtended(const WriteAndReadSpiExtendedVar_t *dataIn, WriteAndReadSpiExtenedReply_t *dataOut)
{
    ReturnCode_t result = RT_INTERNAL_ERROR;

    uint8_t retries = REQUEST_RETRIES;
    do {

        uint8_t *buf = nullptr;
        uint16_t consumed = 0u;
        uint16_t sessionId = 0u;
        bool success = false;

        struct SOMEIP_Header par = {};
        struct SOMEIP_Transmit_Buffer *tb = nullptr;

        uint16_t dataId = 0u;

        if (!CheckAvailability(result))
            return result;

        FunctionEnvironment env(this, m_transmit, false);
        tb = env.GetTxBuffer();

        if (nullptr == tb)
            return RT_INTERNAL_ERROR;

        buf = tb->payload;

        CreateHeader(par, 0x1509, MSGTYPE_REQUEST, false, &sessionId);

        success = SOMEIP_Generator_Fill_Header(&par, buf, SOMEIP_TRANSMIT_MAX_PAYLOAD_LEN, &consumed) &&
                  SOMEIP_Generator_Fill_UINT16(dataId++, dataIn->HandleSpi, &buf[consumed], (SOMEIP_TRANSMIT_MAX_PAYLOAD_LEN - consumed), &consumed) &&
                  SOMEIP_Generator_Fill_UINT32(dataId++, dataIn->WriteId, &buf[consumed], (SOMEIP_TRANSMIT_MAX_PAYLOAD_LEN - consumed), &consumed);

        WriteAndReadSpiElementVar_t *pElement = dataIn->firstElement;
        while (success && NULL != pElement) {
            success =
                SOMEIP_Generator_Fill_UINT16(dataId++, pElement->ReadDataLength, &buf[consumed], (SOMEIP_TRANSMIT_MAX_PAYLOAD_LEN - consumed), &consumed) &&
                SOMEIP_Generator_Fill_BLOB(dataId++, (const uint8_t *) &pElement->WriteData[0], pElement->WriteDataLength, &buf[consumed], (SOMEIP_TRANSMIT_MAX_PAYLOAD_LEN - consumed), &consumed);

            pElement = pElement->next;
        }

        if (success) {
            SOMEIP_Generator_Update_Length(consumed, buf, SOMEIP_TRANSMIT_MAX_PAYLOAD_LEN);
        } else {
            return RT_PARAMETER_NOT_VALID;
        }

        if (!TransmitBuffer(tb, consumed, false, result, sessionId))
            return result;

        if (env.WaitForResponse(&result)) {
            uint16_t parsed = 0u;
            uint16_t tagIgnore = 0;
            uint8_t *pRxBuf = env.GetRxBuffer();
            uint16_t rxBufLen = env.GetRxLength();

            success = SOMEIP_Parser_Read_UINT32(&pRxBuf[parsed], (rxBufLen - parsed), &tagIgnore, &dataOut->ReadId, &parsed);

            WriteAndReadSpiElementReply_t *pElementRx = dataOut->firstElement;
            while (success && (NULL != pElementRx)) {
                pElementRx->ReadDataLength = sizeof(pElementRx->ReadData);
                success = SOMEIP_Parser_Read_BLOB(&pRxBuf[parsed], (rxBufLen - parsed), &tagIgnore, (uint8_t *) &pElementRx->ReadData[0], &pElementRx->ReadDataLength, &parsed);
                pElementRx = pElementRx->next;
            }
        } else {
            env.NoWait();
        }
        retries--;
    } while ((0u != retries) && (RT_TIMEOUT == result));
    return result;
}

static bool AddService(uint8_t *ipAddr, uint8_t ipAddrLen, uint16_t port, uint16_t serviceId, uint16_t instanceId)
{
    bool success = false;
    (void) serviceId;
    /* Find existing client */
    for (LAN866XClientImpl *client : s_clients) {
        if (client->m_ipAddrLength == ipAddrLen) {
            if (0 == memcmp(client->m_ipAddr, ipAddr, ipAddrLen)) {
                if (!client->m_available) {
                    client->m_resetDetected = true;
                    client->m_available = true;
                    for (LAN866XClientListener *listener : client->m_listeners) {
                        LAN866XEventCaller::GetInstance()->RaiseOnDeviceAvailable(listener, client, true);
                    }
                }
                success = true;
                break;
            }
        }
    }
    if (!success) {
        /* Create new client */
        LAN866XClientImpl *client = new LAN866XClientImpl(&s_staticFactory, instanceId, ipAddr, ipAddrLen, port);
        for (LAN866XFactoryListener *listener : s_factoryListeners) {
            LAN866XEventCaller::GetInstance()->RaiseOnNewDeviceFound(listener, client);
        }
        success = true;
    }
    return success;
}

static bool RemoveService(uint8_t *ipAddr, uint8_t ipAddrLen, uint16_t port, uint16_t serviceId)
{
    bool success = false;
    (void) port;
    (void) serviceId;
    for (LAN866XClientImpl *client : s_clients) {
        if (client->m_ipAddrLength == ipAddrLen) {
            if (0 == memcmp(client->m_ipAddr, ipAddr, ipAddrLen)) {
                client->m_available = false;
                for (LAN866XClientListener *listener : client->m_listeners) {
                    LAN866XEventCaller::GetInstance()->RaiseOnDeviceAvailable(listener, client, false);
                }
                success = true;
                break;
            }
        }
    }
    return success;
}

static bool ReportReset(uint8_t *ipAddr, uint8_t ipAddrLen, uint16_t port, uint16_t serviceId)
{
    bool success = false;
    (void) port;
    (void) serviceId;
    for (LAN866XClientImpl *client : s_clients) {
        if (client->m_ipAddrLength == ipAddrLen) {
            if (0 == memcmp(client->m_ipAddr, ipAddr, ipAddrLen)) {
                client->m_resetDetected = true;
                client->m_available = true;
                for (LAN866XClientListener *listener : client->m_listeners) {
                    LAN866XEventCaller::GetInstance()->RaiseOnDeviceReset(listener, client);
                }
                success = true;
                break;
            }
        }
    }
    return success;
}

static void
OnSomeIpEvent(enum SOMEIP_CB_Event evnt, struct SOMEIP_Server_Client *pServerClient, struct SOMEIP_IpAddr *pIp, uint16_t receivedInstanceId, struct SOMEIP_OptConfig *pConfig, void *eventData)
{
    (void) pConfig;
    (void) eventData;
    if (EV_CLIENT_REMOTE_RESET_DETECTED == evnt) {
        ReportReset(pIp->sourceAddr, 4u, pIp->port, pServerClient->serviceId);
    } else if (EV_CLIENT_SERVICE_AVAILABLE == evnt) {
        if (!AddService(pIp->sourceAddr, 4u, pIp->port, pServerClient->serviceId, receivedInstanceId)) {
            SOMEIP_CB_Log("Client: Service is available, but can not be handled due to lag of resurces");
        }
    } else if (EV_CLIENT_SERVICE_STOPPED == evnt) {
        RemoveService(pIp->sourceAddr, 4u, pIp->port, pServerClient->serviceId);
    }
}

static void OnTransmitResult(struct SOMEIP_Transmit_Buffer *pBuf, bool success, enum SOMEIP_ReturnCode retCode, const uint8_t *pRxBuf, uint16_t rxBufLen)
{
    if (nullptr != pBuf->callbackTag) {
        FunctionEnvironment *env = (FunctionEnvironment *) pBuf->callbackTag;
        if (FunctionEnvironment::IsValid(env)) {
            ep_wait_vars *pWait = env->GetWait();
            if (pWait) {
                pWait->success = success;
                pWait->retCode = retCode;
                if (success && (nullptr != pRxBuf) && (0u != rxBufLen)) {
                    if (rxBufLen <= sizeof(pWait->rxBuf)) {
                        (void) memcpy(pWait->rxBuf, pRxBuf, rxBufLen);
                        pWait->rxLen = rxBufLen;
                    } else {
                        SOMEIP_CB_Log("RX buffer too small");
                        pWait->rxLen = 0u;
                    }
                } else {
                    pWait->rxLen = 0u;
                }
                SOMEIP_CB_SemPost(&pWait->semWaitForAck);
            }
        }
    }
}

/**********************************/
/* Generated RPC Event Dispatcher */
/**********************************/

static enum SOMEIP_ReturnCode OnDataReceived(const uint8_t *b, uint16_t bLen, struct SOMEIP_IpAddr *pIp, void *rxTag)
{
    struct SOMEIP_Header par;
    enum SOMEIP_ReturnCode result;
    uint16_t parsed = 0u; /* SOME/IP Header will be parsed during this function */
    (void) rxTag;

    LAN866XClientImpl *client = LAN866XClientImpl::GetByIpAdress(pIp->destinAddr, 4);
    if (!client) {
        client = LAN866XClientImpl::GetByIpAdress(pIp->sourceAddr, 4);
    }
    if (!client) {
        return SOMEIP_E_NOT_REACHABLE;
    }

    result = SOMEIP_Parser_Read_Header(b, bLen, &par, &parsed);

    if (result != SOMEIP_E_OK) {
        return SOMEIP_E_MALFORMED_MESSAGE;
    }

    switch (par.serviceId) {
        case 0xff10: /* LAN866X */
        {
            if (par.interfaceVersion == 0x1) {
                if ((MSGTYPE_RESPONSE == par.msgType) || (MSGTYPE_ERROR == par.msgType)) {
                    SOMEIP_Transmit_ReceivedResponse(client->m_ipAddr, client->m_transmit, par.sessionId, par.retCode, &b[parsed], bLen - parsed);
                    result = SOMEIP_E_OK;
                    break;
                }

                if ((MSGTYPE_NOTIFICATION == par.msgType) && (par.generateEvent) && (SOMEIP_E_OK == par.retCode)) {
                    switch (par.methodId) {
                        case 0x8020: /* OnTDMeasurementCompleted */
                            client->DecodeResponse_OnTDMeasurementCompleted(&b[parsed], bLen - parsed);
                            break;

                        case 0x8000: /* OnGpioEvents */
                            client->DecodeResponse_OnGpioEvents(&b[parsed], bLen - parsed);
                            break;

                        case 0x8010: /* OnUartReceive */
                            client->DecodeResponse_OnUartReceive(&b[parsed], bLen - parsed);
                            break;

                        default:
                            result = SOMEIP_E_UNKNOWN_METHOD;
                            break;
                    }
                } else {
                    result = SOMEIP_E_WRONG_MESSAGE_TYPE;
                }
            } else {
                result = SOMEIP_E_WRONG_INTERFACE_VERSION;
            }
            break;
        }
        default: {
            result = SOMEIP_E_UNKNOWN_SERVICE;
            break;
        }
    }

    return result;
}
